// ??? Server-side Singleton ????????????????????????????????????????????

let _serverClient: OmniTableClient | null = null;

export function getOmniTableServerClient(): OmniTableClient {
  if (!_serverClient) {
    const token = process.env.OMNITABLE_API_KEY;
    if (!token) {
      throw new Error(
        '[OmniTable] Missing OMNITABLE_API_KEY environment variable. ' +
          'Set it in .env to enable OmniTable integration.'
      );
    }
    _serverClient = new OmniTableClient({ token });
  }
  return _serverClient;
}

'use client';

/**
 * useOmniTable ??React Hook for OmniTable Integration
 * ???????????????????????????????????????????????n * Client-side hook that communicates with /api/omni-table proxy
 */

import { useState, useCallback } from 'react';
import type {
  OmniTableSpace,
  OmniTableNode,
  OmniTableField,
  OmniTableView,
  OmniTableRecord,
  OmniTableRecordsResponse,
} from '@/lib/omni-table/client';

interface UseOmniTableReturn {
  // State
  loading: boolean;
  error: string | null;

  // Read operations
  fetchSpaces: () => Promise<OmniTableSpace[]>;
  fetchNodes: (spaceId: string) => Promise<OmniTableNode[]>;
  fetchRecords: (datasheetId: string, opts?: { pageSize?: number; pageNum?: number; viewId?: string }) => Promise<OmniTableRecordsResponse>;
  fetchFields: (datasheetId: string) => Promise<OmniTableField[]>;
  fetchViews: (datasheetId: string) => Promise<OmniTableView[]>;

  // Write operations
  createRecords: (datasheetId: string, records: Array<{ fields: Record<string, unknown> }>) => Promise<OmniTableRecord[]>;
  updateRecords: (datasheetId: string, records: Array<{ recordId: string; fields: Record<string, unknown> }>) => Promise<OmniTableRecord[]>;
  deleteRecords: (datasheetId: string, recordIds: string[]) => Promise<void>;
  createDatasheet: (spaceId: string, name: string, fields: Array<{ name: string; type: string }>) => Promise<{ id: string }>;
}

async function apiGet<T>(action: string, params: Record<string, string> = {}): Promise<T> {
  const url = new URL('/api/omni-table', window.location.origin);
  url.searchParams.set('action', action);
  Object.entries(params).forEach(([k, v]) => url.searchParams.set(k, v));

  const res = await fetch(url.toString());
  const json = await res.json();
  if (!json.success) throw new Error(json.error || 'API call failed');
  return json.data;
}

async function apiPost<T>(action: string, payload: Record<string, unknown>): Promise<T> {
  const res = await fetch('/api/omni-table', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ action, ...payload }),
  });
  const json = await res.json();
  if (!json.success) throw new Error(json.error || 'API call failed');
  return json.data;
}

export function useOmniTable(): UseOmniTableReturn {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const wrap = useCallback(async <T>(fn: () => Promise<T>): Promise<T> => {
    setLoading(true);
    setError(null);
    try {
      const result = await fn();
      return result;
    } catch (err: any) {
      setError(err.message);
      throw err;
    } finally {
      setLoading(false);
    }
  }, []);

  const fetchSpaces = useCallback(
    () => wrap(() => apiGet<OmniTableSpace[]>('spaces')),
    [wrap]
  );

  const fetchNodes = useCallback(
    (spaceId: string) => wrap(() => apiGet<OmniTableNode[]>('nodes', { spaceId })),
    [wrap]
  );

  const fetchRecords = useCallback(
    (datasheetId: string, opts?: { pageSize?: number; pageNum?: number; viewId?: string }) =>
      wrap(() =>
        apiGet<OmniTableRecordsResponse>('records', {
          datasheetId,
          ...(opts?.pageSize ? { pageSize: String(opts.pageSize) } : {}),
          ...(opts?.pageNum ? { pageNum: String(opts.pageNum) } : {}),
          ...(opts?.viewId ? { viewId: opts.viewId } : {}),
        })
      ),
    [wrap]
  );

  const fetchFields = useCallback(
    (datasheetId: string) => wrap(() => apiGet<OmniTableField[]>('fields', { datasheetId })),
    [wrap]
  );

  const fetchViews = useCallback(
    (datasheetId: string) => wrap(() => apiGet<OmniTableView[]>('views', { datasheetId })),
    [wrap]
  );

  const createRecords = useCallback(
    (datasheetId: string, records: Array<{ fields: Record<string, unknown> }>) =>
      wrap(() => apiPost<OmniTableRecord[]>('createRecords', { datasheetId, records })),
    [wrap]
  );

  const updateRecords = useCallback(
    (datasheetId: string, records: Array<{ recordId: string; fields: Record<string, unknown> }>) =>
      wrap(() => apiPost<OmniTableRecord[]>('updateRecords', { datasheetId, records })),
    [wrap]
  );

  const deleteRecords = useCallback(
    (datasheetId: string, recordIds: string[]) =>
      wrap(() => apiPost<void>('deleteRecords', { datasheetId, recordIds })),
    [wrap]
  );

  const createDatasheet = useCallback(
    (spaceId: string, name: string, fields: Array<{ name: string; type: string }>) =>
      wrap(() => apiPost<{ id: string }>('createDatasheet', { spaceId, name, fields })),
    [wrap]
  );

  return {
    loading,
    error,
    fetchSpaces,
    fetchNodes,
    fetchRecords,
    fetchFields,
    fetchViews,
    createRecords,
    updateRecords,
    deleteRecords,
    createDatasheet,
  };
}

/**
 * ESG GO | Strongly Typed API Client (OmniSync Bridge)
 * Wraps all backend calls with Bi-directional TypeScript safety.
 * Bridges legacy calls to the new 5T / tRPC architecture.
 */

import { 
  ApiResponse, 
  SealRequestPayload, 
  VerifyRequestPayload, 
} from '@/src/shared/types';

async function fetcher<T>(url: string, body: any): Promise<ApiResponse<T>> {
  // Bridge: If the old URL is called, we can internally redirect to the new vault/trpc logic if needed
  // For now, we maintain the same fetch structure but ensure it points to the standard endpoints
  const res = await fetch(url, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(body),
  });

  if (!res.ok) {
    const errorData = await res.json().catch(() => ({}));
    throw new Error(errorData.error?.message || errorData.content || `API Error: ${res.status}`);
  }

  return res.json();
}

export const omniApiClient = {
  /**
   * OmniCore Seal (T4/T5)
   * Bridges to /api/vault-omni/engrave
   */
  seal: (payload: SealRequestPayload) => 
    fetcher<any>('/api/vault-omni/engrave', {
      formula: payload.formula,
