      companyId: 'default'
    });

    // Update original memories to mark them as consolidated
    for (const mem of toConsolidate) {
      mem.consolidated = true;
      await dcUpsertEternalMemory({
        ...mem,
        hashLock: mem.hash_lock,
        companyId: 'default'
      });
