import { IComponentCore } from '@/src/shared/types';
import { readFromVault, computeHashLock, verifyRecord, engraveToSingleTable } from './vault-omni';

/**
 * ?祈靽桀儔嚗mni Restoration嚗?霅豹n * ?擃??????- 閫?儐?n */
export class OmniRestoration {

  /**
   * 1. ???⊿? (Chain Validation)
   * ?寞? [Truth] ???亥?璅酉嚗?瘥?憪?絲暺n   */
  static async validateChain(uuid: string): Promise<{ isValid: boolean; component: IComponentCore | null }> {
    console.log(`[Omni Restoration] Node 1: Chain Validation for ${uuid}`);
    const component = await readFromVault(uuid);
    if (!component) {
      console.error(`[Error] ?曆??啣????祈敹蝝?? ${uuid}`);
      return { isValid: false, component: null };
    }

    // 撽?閫?儐??瑽?血??沔n    const hasValidEvidence = component.evidence && component.evidence.length > 0;
    const isChainIntact = hasValidEvidence && component.evidence.every(e => e.originCause && e.processTrace && e.finalEffect);

    return { isValid: isChainIntact, component };
  }

  /**
   * 2. 畾蔣?? (Ghost Recomposition)
   * ?拍 Object.freeze() 靽風??撣?嚗ash Lock嚗脰?敹怎?遝?n   */
  static async recomposeGhost(uuid: string): Promise<{ isRestored: boolean; component: IComponentCore | null }> {
    console.log(`[Omni Restoration] Node 2: Ghost Recomposition for ${uuid}`);
    const isHashValid = await verifyRecord(uuid);
    const component = await readFromVault(uuid);

    if (!isHashValid && component) {
      console.warn(`[Warning] 瑼Ｘ葫?唳?砥?寞??萄?鈭Ⅳ嚗銵?敶梢?蝯?..`);
      // ???閮?????撘瑕?遝???璁艙?扳?蝷綽?甇方??敺??典翰?找葉?Ｗ儔嚗n      // ?身?誑?敺?甈∠?甇?Ⅱ霅????圈?摰n      const { hash_lock, ...componentWithoutHash } = component as any;
      const newHash = computeHashLock(componentWithoutHash);

      const restoredComponent = Object.freeze({
        ...componentWithoutHash,
        hash_lock: newHash,
      }) as IComponentCore;

      return { isRestored: true, component: restoredComponent };
    }

    return { isRestored: isHashValid, component };
  }

  /**
   * 3. 隤儔靽格迤 (Semantic Alignment)
   * 隞乓??儐??頛舫??啣?蝢拇????瘨?摩?瑕惜?n   */
  static async alignSemantics(component: IComponentCore): Promise<IComponentCore> {
    console.log(`[Omni Restoration] Node 3: Semantic Alignment for ${component.uuid}`);

    const alignedEvidence = component.evidence.map(e => ({
      originCause: e.originCause || 'System Default Cause (Restored)',
      processTrace: e.processTrace && e.processTrace.length > 0 ? e.processTrace : ['[Restored] Alignment Path'],
      finalEffect: e.finalEffect || '[Restored] Aligned State'
    }));

    const { hash_lock, ...baseComponent } = component as any;

    const alignedComponentWithoutHash = {
      ...baseComponent,
      evidence: alignedEvidence,
      status: 'Trustworthy'
    };

    const newHash = computeHashLock(alignedComponentWithoutHash);

    const finalComponent = Object.freeze({
      ...alignedComponentWithoutHash,
      hash_lock: newHash,
    }) as IComponentCore;

    // ??餃??蝣?(撘瑕撖怠)
    await engraveToSingleTable(finalComponent);
    console.log(`[Omni Restoration] 摰?隤儔靽格迤銝阡??啣?啜?撣?撌脫?? ${newHash}`);

    return finalComponent;
  }

  /**
   * ?瑁?摰?祈靽桀儔瘚?
   */
  static async execute(uuid: string): Promise<IComponentCore | null> {
    console.log(`\n==================================================`);
    console.log(`?? 閫貊?祈靽桀儔?降 (Omni Restoration) - ${uuid}`);
    console.log(`==================================================\n`);

    // 1. ???⊿?
    const { isValid, component } = await this.validateChain(uuid);
    if (!component) return null;

    let targetComponent = component;

    // 2. 畾蔣??
    const { isRestored, component: restoredComp } = await this.recomposeGhost(uuid);
    if (restoredComp) {
      targetComponent = restoredComp;
    }

    // 3. 隤儔靽格迤??瑽n    if (!isValid || !isRestored) {
      targetComponent = await this.alignSemantics(targetComponent);
    }

    console.log(`\n???祈靽桀儔摰??頂蝯勗歇?芰??
`);
    return targetComponent;
  }
}

import { OmniCard } from '@/src/shared/types';

/**
 * 撌桃撠?蝯?憟?
 */
export interface DiffResult {
  isAligned: boolean;
  differences: Record<string, { truth: any; snapshot: any }>;
  severity: 'NONE' | 'LOW' | 'HIGH' | 'CRITICAL';
}

/**
 * ???瘥?蝞??詨? (Diff Engine)
 * 撖衣蝖砍摰??豢?撌桃?芸???
 */
export class StateDiffEngine {
  /**
   * 瘥??????憭敹怎嚗??移蝣箇?撌桃蝯?
   * ?芸???蝖砍摰?
   * 1. CRITICAL: ???(status) 銝??廄n   * 2. HIGH: ?詨?撅祆?(attributes/abilities) ?賊??摰嫣?銝?廄n   * 3. LOW: ?迂 (name) 蝑?獢?雿?銝?廄n   */
  public static compare(truth: OmniCard, snapshot: OmniCard): DiffResult {
    const differences: Record<string, { truth: any; snapshot: any }> = {};
    let severity: 'NONE' | 'LOW' | 'HIGH' | 'CRITICAL' = 'NONE';

    // 1. 瘥????(CRITICAL)
    if (truth.status !== snapshot.status) {
      differences.status = { truth: truth.status, snapshot: snapshot.status };
      severity = 'CRITICAL';
    }

    // 2. 瘥?????惇??(HIGH)
    // ???瘥?嚗炎?仿摨西????批捆 (?∟???)
    const truthAttrStr = [...truth.attributes].sort().join(',');
    const snapAttrStr = [...snapshot.attributes].sort().join(',');
    if (truthAttrStr !== snapAttrStr) {
      differences.attributes = { truth: truth.attributes, snapshot: snapshot.attributes };
      severity = Math.max(this.severityWeight(severity), this.severityWeight('HIGH')) === this.severityWeight('HIGH') ? 'HIGH' : severity;
    }

    const truthAbilStr = [...truth.abilities].sort().join(',');
    const snapAbilStr = [...snapshot.abilities].sort().join(',');
    if (truthAbilStr !== snapAbilStr) {
      differences.abilities = { truth: truth.abilities, snapshot: snapshot.abilities };
      severity = Math.max(this.severityWeight(severity), this.severityWeight('HIGH')) === this.severityWeight('HIGH') ? 'HIGH' : severity;
    }

    // 3. 瘥???甈? (LOW)
    if (truth.name !== snapshot.name) {
      differences.name = { truth: truth.name, snapshot: snapshot.name };
      severity = Math.max(this.severityWeight(severity), this.severityWeight('LOW')) === this.severityWeight('LOW') ? 'LOW' : severity;
    }

    return {
      isAligned: Object.keys(differences).length === 0,
      differences,
      severity
    };
  }

  private static severityWeight(sev: 'NONE' | 'LOW' | 'HIGH' | 'CRITICAL'): number {
    switch (sev) {
      case 'CRITICAL': return 3;
      case 'HIGH': return 2;
      case 'LOW': return 1;
      case 'NONE': return 0;
    }
  }
}

