/**
 * HealingResult: ?典?隤踹??芰?蝯?憟?
 */
export interface HealingResult {
  status: 'SUCCESS' | 'PARTIAL' | 'FAILED';
  reconciledCount: number;
  logs: string[];
}

export type HealingLevel = 'LV1_MONITOR' | 'LV2_AUTO_HEAL' | 'LV3_QUANTUM_LOCK';

/**
 * IAdapterNode: ?啗釭憭鞈?皞?蝭暺n * 瘥?暺誨銵典??典像??(憒?Notion ??AlTable) ???祕擃??質◤???◤撘瑕靽桀儔
 */
export interface IAdapterNode {
  platform: 'Notion' | 'AlTable';
  id: string; // 憭????? ID (e.g. page_id, record_id)
  cardUuid: string; // 撠??唳??頂蝯曹葉?銝?∠? UUID (Traceable)

  /**
   * ??閰脣??函?暺銝??∠?敹怎
   */
  getSnapshot(): Promise<OmniCard>;

  /**
   * 撠??函?暺???撥?嗆??(Heal) ?箇????n   */
  heal(truthState: OmniCard): Promise<void>;

  /**
   * ????嚗??暺?撖怠甈?嚗蝭情??αn   */
  lock?(): Promise<void>;
}

/**
 * IGlobalHealing: ?典????詨??降?
 */
export interface IGlobalHealing {
  scanAllEntities(): Promise<Map<string, OmniCard>>;
  compareWithGPL(): Promise<Map<string, { truth: OmniCard | null; snapshot: OmniCard; node: IAdapterNode }>>;
  applyHealing(): Promise<HealingResult>;
}

/**
 * GlobalHealing: ?祈敹?典??芣?隤踹??沔n * ?詨?璈?萄儐 5T ?降?嚗鞈??郁?脰??芸???n */
export class GlobalHealing implements IGlobalHealing {
  private adapterNodes: IAdapterNode[] = [];
  private eventStore: EventStore;
  private healingLevel: HealingLevel;

  constructor(eventStore: EventStore, healingLevel: HealingLevel = 'LV2_AUTO_HEAL') {
    this.eventStore = eventStore;
    this.healingLevel = healingLevel;
  }

  /**
   * 閮餃?銝??蝭暺隤踹?蝬脰楝銝苒n   */
  public registerNode(node: IAdapterNode): void {
    this.adapterNodes.push(node);
  }

  /**
   * 皜撌脰酉??蝭暺?(皜祈岫?頛)
   */
  public clearNodes(): void {
    this.adapterNodes = [];
  }

  /**
   * 1. ?典???嚗?甇瑟???蝭暺????嗡???翰??(Tangible)
   */
  public async scanAllEntities(): Promise<Map<string, OmniCard>> {
    const snapshots = new Map<string, OmniCard>();
    for (const node of this.adapterNodes) {
      try {
        const snapshot = await node.getSnapshot();
        snapshots.set(node.cardUuid, snapshot);
      } catch (err: any) {
        throw new Error(`[?典???憭望?] ?⊥?敺?${node.platform} 蝭暺?(${node.id}) ??敹怎: ${err?.message || err}`);
      }
    }
    return snapshots;
  }

  /**
   * 2. 皞舀??⊿?嚗???GPL ??隞嗆?嚗?撱箄府?∠???????Truth State)嚗?蝯垢?脰?瘥? (Traceable)
   */
  public async compareWithGPL(): Promise<Map<string, { truth: OmniCard | null; snapshot: OmniCard; node: IAdapterNode }>> {
    const comparison = new Map<string, { truth: OmniCard | null; snapshot: OmniCard; node: IAdapterNode }>();

    for (const node of this.adapterNodes) {
      const snapshot = await node.getSnapshot();
      const truth = this.eventStore.rebuildTruthState(node.cardUuid);
      comparison.set(node.cardUuid, { truth, snapshot, node });
    }

    return comparison;
  }

  /**
   * 3. 撌桃?怠像 (Healing)嚗蝯垢?豢???????撘瑕?澆?拚??其耨敺抬?蝣箔?鞈?銝??(Transparent)
   */
  public async applyHealing(): Promise<HealingResult> {
    const logs: string[] = [];
    let reconciledCount = 0;
    let failedCount = 0;

    logs.push(`[?典???] ??隤踹??芰?璈 (甈?蝑?: ${this.healingLevel})嚗酉??暺: ${this.adapterNodes.length}`);

    try {
      const comparison = await this.compareWithGPL();

      for (const [cardUuid, { truth, snapshot, node }] of Array.from(comparison.entries())) {
        let currentTruth = truth;

        // 1. ?郊撘? (Sync Engine)嚗 GPL 蝻箏仃嚗誑蝯垢敹怎?箸?鋆皞舀??n        if (!currentTruth) {
          logs.push(`[?郊鋆] ?∠? ${cardUuid} ??GPL 銝剔撩銋????哨??芸?隞亙翰?批遣蝡?憪滲皞?隞嗚);
          await this.eventStore.appendEvent(cardUuid, 'CARD_CREATED', snapshot, node.platform);
          currentTruth = snapshot;
          continue; // 撌脰??剁?甇斗??∪榆?豹n        }

        // 2. ???瘥?(Diff Engine)
        const diffResult = StateDiffEngine.compare(currentTruth, snapshot);

        if (diffResult.isAligned) {
          logs.push(`[銝?弼 ??GPL ??????典????⊿??怠像?);
        } else {
          logs.push(`[?] 瑼Ｘ葫?唳??撌殷??湧?蝔漲: ${diffResult.severity}`);
          logs.push(`  - 撌桃閰單?: ${JSON.stringify(diffResult.differences)}`);

          // 3. ?寞?甈?蝑? (Healing Level) 瘙箏??蔭蝑
          if (this.healingLevel === 'LV1_MONITOR') {
            logs.push(`[??] LV1 璅∪?嚗?蝝?榆?堆?銝脰??芸??怠像?);
            await this.eventStore.appendEvent(cardUuid, 'HEALING_LOGGED', snapshot, 'Omni-Avatar');
            continue;
          }

          if (this.healingLevel === 'LV3_QUANTUM_LOCK' && diffResult.severity === 'CRITICAL') {
            logs.push(`[????] 瑼Ｘ葫??CRITICAL 銵?嚗???LV3 瘛勗漲?脫情??摰??怠?蝭暺神?交??);
            if (node.lock) {
              await node.lock();
            }
            await this.eventStore.appendEvent(cardUuid, 'QUANTUM_LOCKED', currentTruth, 'Omni-Avatar');
            failedCount++; // ??閬?芾?怠像嚗?鈭箏極隞
            continue;
          }

          // LV2 ??LV3 ??CRITICAL ?榆?堆??脰?撘瑕靽桀儔
          try {
            await node.heal(currentTruth);
            reconciledCount++;
            logs.push(`[??] 撌桃?怠像摰?嚗歇撘瑕?湔 ${node.platform} 蝭暺?(${node.id}) ?喟????);

            // ???亥?蝟餌絞嚗?????蝔?? GPL 銝苒n            await this.eventStore.appendEvent(cardUuid, 'HEALING_APPLIED', currentTruth, 'Omni-Avatar');
          } catch (error: any) {
            failedCount++;
            logs.push(`[?航炊] ?怠像蝭暺?${node.platform} (${node.id}) 憭望?: ${error?.message || error}`);
            await this.eventStore.appendEvent(cardUuid, 'HEALING_FAILED', snapshot, 'Omni-Avatar');
          }
        }
      }

      let status: 'SUCCESS' | 'PARTIAL' | 'FAILED' = 'SUCCESS';
      if (failedCount > 0) {
        status = reconciledCount > 0 ? 'PARTIAL' : 'FAILED';
      }

      logs.push(`[隤踹?蝯?] ??? ${status}, ??靽桀儔蝭暺: ${reconciledCount}, 憭望?蝭暺: ${failedCount}`);

      return {
        status,
        reconciledCount,
        logs,
      };
    } catch (e: any) {
      logs.push(`[?賡?批仃? ?典?隤踹???銝剔????航炊: ${e?.message || e}`);
      return {
        status: 'FAILED',
        reconciledCount: 0,
        logs,
      };
    }
  }
}

import { getSupabaseClient } from '../supabase';
import { OmniEventStore } from './event-store';
import { genkit } from 'genkit';
import { googleAI, textEmbedding004 } from '@genkit-ai/googleai';

// Initialize Genkit
const ai = genkit({
  plugins: [googleAI()], // Assumes process.env.GEMINI_API_KEY is available or setup elsewhere
});

export interface EpisodicMemory {
  id?: string;
  sourceOrigin: string;
  eventType: string;
  content: string;
  metadata?: Record<string, any>;
  embedding?: number[];
  createdAt?: string;
}

export class OmniMemorySync {
  /**
   * Syncs an episodic event to the database (and optionally extracts/generates vector embeddings)
   */
  public static async syncEpisodicMemory(
    memory: EpisodicMemory,
    options?: { signal?: AbortSignal }
  ): Promise<void> {
    const signal = options?.signal;

    // 1. ?瑁??炎?伐?憒?隞餃?撌脣?瘨??湔銝剜嚗???Token ???n    if (signal?.aborted) {
      console.log(`[OmniMemorySync] Operation aborted before starting: ${memory.sourceOrigin}`);
      return;
    }

    console.log(`[OmniMemorySync] Syncing memory for source: ${memory.sourceOrigin}`);

    let vector: number[] | undefined = memory.embedding;

    try {
      if (!vector && memory.content) {
        console.log('[OmniMemorySync] Generating embedding via Genkit...');

        const embedPromise = ai.embed({
          embedder: textEmbedding004,
          content: memory.content,
        }).then(res => res[0].embedding);

        // 2. ?瑁?銝剜??迎??拍 Promise.race 霈遙??函?敺芋?????◤撘瑁?銝剜
        if (signal) {
          vector = await Promise.race([
            embedPromise,
            new Promise<number[]>((_, reject) => {
              const onAbort = () => reject(new Error('AbortError: Genkit embedding request was cancelled by client'));
              signal.addEventListener('abort', onAbort);
              // 皜????剁??踹? Memory Leak
              embedPromise.finally(() => signal.removeEventListener('abort', onAbort));
            })
          ]);
        } else {
          vector = await embedPromise;
        }

        console.log('[OmniMemorySync] Embedding generated successfully.');
      }
    } catch (err) {
      console.warn('[OmniMemorySync] Failed to generate embedding:', err);
    }

    const client = getSupabaseClient();
    if (!client) {
      console.warn('[OmniMemorySync] Supabase client not available, skipping db sync.');
      return;
    }

    try {
      const { data, error } = await client.from('episodic_memories').insert({
        source_origin: memory.sourceOrigin,
        event_type: memory.eventType,
        content: memory.content,
        metadata: memory.metadata || {},
        embedding: vector || null,
        created_at: memory.createdAt || new Date().toISOString()
      });

      if (error) {
        console.error('[OmniMemorySync] Failed to sync to Supabase:', error.message);
      }
    } catch (err) {
      console.error('[OmniMemorySync] Sync error:', err);
    }
  }

  /**
   * Listen to OmniEventStore and auto-sync events as Episodic Memories
   */
  public static initAutoSync() {
    OmniEventStore.eventBus.on('event_saved', (event) => {
      this.syncEpisodicMemory({
        sourceOrigin: event.source_platform,
        eventType: event.event_type,
        content: JSON.stringify(event.payload),
        metadata: {
          omni_card_uuid: event.omni_card_uuid,
          hash_lock: event.hash_lock
        },
        createdAt: new Date(event.created_at).toISOString()
      }).catch((err) => {
        console.error(`[OmniMemorySync] Auto-sync failed for event ${event.id}:`, err);
      });
    });
    console.log('[OmniMemorySync] Auto-sync initialized.');
  }
}

