        if (!global.crypto) (global as any).crypto = {};
        global.crypto.randomUUID = vi.fn().mockReturnValue('mock-uuid-1234') as any;

        // 撱箇??臭誑?舀???澆 (Chaining) ??Mock Channel
        mockChannel = {
            on: vi.fn().mockImplementation((event_type, filter, cb) => {
