                    capturedPresenceSyncCb = cb;
                }
                return mockChannel; // ?舀 .on().on() ???澆
            }),
            subscribe: vi.fn().mockImplementation((cb: Function) => cb('SUBSCRIBED')),
            unsubscribe: vi.fn(),
