            }),
        };

        (supabase.channel as any).mockReturnValue(mockChannel);

        // 璅⊥ UI ?喲脖???Callbacks
        mockCallbacks = {
            onPresenceSync: vi.fn(),
            onEventReceived: vi.fn(),
            onStatusChange: vi.fn(),
        };

        service = new SupabaseOmniRealtimeService();
    });

    afterEach(() => {
        global.fetch = originalFetch;
