/**
 * ?澆 Slack Web API
 */
async function callSlackAPI<T = unknown>(
  method: string,
  body: Record<string, unknown>
): Promise<T> {
  if (!SLACK_BOT_TOKEN) {
    throw new Error('[SlackGateway] SLACK_BOT_TOKEN ?芾身摰?隢 .env 銝剖??乓?);
  }

  const res = await fetch(`${SLACK_API}/${method}`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json; charset=utf-8',
      Authorization: `Bearer ${SLACK_BOT_TOKEN}`,
    },
    body: JSON.stringify(body),
  });

  if (!res.ok) {
    throw new Error(`[SlackGateway] HTTP ?航炊 ${res.status} on ${method}`);
  }

  const data = await res.json() as { ok: boolean; error?: string } & T;
  if (!data.ok) {
    throw new Error(`[SlackGateway] Slack API ?航炊: ${data.error} (method: ${method})`);
  }
  return data;
}

