/**
 * ESGSonar | Version Difference Engine
 * Handles comparison between regulation/report versions.
 */

export type DiffMode = 'word' | 'line' | 'char';

export interface DiffResult {
  added: string[];
  removed: string[];
  changed: boolean;
  count: number;
  unifiedDiff?: string;
  esgTags?: string[];
}

export class DiffEngine {
  /**
   * Simple line-based comparison
   */
  static compareLines(oldText: string, newText: string): DiffResult {
    const oldLines = oldText.split('\n');
    const newLines = newText.split('\n');

    const added = newLines.filter(l => !oldLines.includes(l) && l.trim().length > 0);
    const removed = oldLines.filter(l => !newLines.includes(l) && l.trim().length > 0);

    return {
      added,
      removed,
      changed: added.length > 0 || removed.length > 0,
      count: added.length + removed.length,
      esgTags: this.detectESGTags([...added, ...removed])
    };
  }

  /**
   * Structured JSON comparison
   */
  static compareJSON(oldObj: any, newObj: any): boolean {
    return JSON.stringify(oldObj) !== JSON.stringify(newObj);
  }

  /**
   * Detect ESG-related keywords in changes
   */
  private static detectESGTags(texts: string[]): string[] {
    const tags = new Set<string>();
    const content = texts.join(' ').toLowerCase();

    const patterns = {
      'E': ['蝣?, '?', '?賣?', '??', '撱Ｘ???, '瘙⊥?', '瘞??, 'environment', 'carbon', 'emission'],
      'S': ['鈭箸?', '?極', '摰', '?寡?', '蝷曉?', '憭?', 'social', 'human rights', 'safety', 'diversity'],
      'G': ['瘝餌?', '???', '憸券', '??', '?噸', '??', 'governance', 'board', 'risk', 'compliance']
    };

    Object.entries(patterns).forEach(([category, keywords]) => {
      if (keywords.some(k => content.includes(k))) {
        tags.add(category);
      }
    });

    return Array.from(tags);
  }
}

import { createHash, createHmac, timingSafeEqual } from 'crypto';

/**
 * ESGSonar | Hash Lock Mechanism
 * Provides secure content hashing, version detection, and HMAC support.
 */

export class HashLock {
  /**
   * Generate SHA-256 hash for content
   */
  static sha256(content: string | Buffer): string {
    return createHash('sha256').update(content as any).digest('hex');
  }

  /**
   * Generate SHA-512 hash for extra security
   */
  static sha512(content: string | Buffer): string {
    return createHash('sha512').update(content as any).digest('hex');
  }

  /**
   * Generate HMAC for authenticated content
   */
  static hmac(content: string | Buffer, secret: string): string {
    return createHmac('sha256', secret).update(content as any).digest('hex');
  }

  /**
   * Constant-time comparison to prevent timing attacks
   */
  static secureCompare(a: string, b: string): boolean {
    const bufA = Buffer.from(a);
    const bufB = Buffer.from(b);
    if (bufA.length !== bufB.length) return false;
    return timingSafeEqual(new Uint8Array(bufA), new Uint8Array(bufB));
  }

  /**
   * Check if content has changed against a stored hash
   */
  static hasChanged(currentContent: string, storedHash: string): boolean {
    const currentHash = this.sha256(currentContent);
    return !this.secureCompare(currentHash, storedHash);
  }

  /**
   * Generate a batch hash lock for multiple items
   */
  static batchHash(items: any[]): string {
    const payload = JSON.stringify(items.sort());
    return this.sha256(payload);
  }
}

